import React from "react";
import "../styles/About.css";

export default function About() {
  return (
    <div className="about-us">
      <div className="about-heading">About Us</div>
      <p className="about-txt">
        We, Society Associates, operating from Kalyan, Maharashtra, are a
        multidisciplinary team of accounting and audit professionals with deep,
        sector-specific experience. We offer a range of services to meet the
        complex and evolving accounting and auditing challenges that you may
        face on multiple fronts. Out mission is to provide clients with the 'best
        Accounting & Auditing Solution' for all their businesses, financial and regulatory
        requirements.
      </p>
    </div>
  );
}
